      { "from": "Payment Event Consumer", "to": "Payment Database", "status": "correct", "issue": "Circuit breaker with 60s reset window is in place. Acceptable for a downstream dependency." },
      { "from": "Payment Event Consumer", "to": "Dead-letter topic (payment.events.dlq)", "status": "risk", "issue": "The DLQ is undermined by the early offset commit. If the consumer crashes before even reaching the retry logic, the event is lost silently — it never reaches the DLQ and never gets reprocessed. The safety net has a hole." }
    ],
    "contract_compliance": "The service structurally implements the expected consumer contract (consume, process, DLQ on failure), but the offset commit ordering violates the fundamental delivery guarantee required for financial event processing.",
    "data_flow_integrity": "COMPROMISED. The commit-before-process pattern creates a window where payment events can be silently dropped. For a payment system, every event must be accounted for — either successfully processed, in the DLQ, or still pending on the topic. The current design allows a fourth state: lost."
  },

  "observability_review": {
    "logging": { "coverage": "adequate", "gaps": ["No mention of logging when an event is lost due to crash-after-commit-before-process — this failure mode is currently invisible", "Should log offset commit separately from event receipt to aid post-incident forensics"] },
