      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database migrations mentioned. Consumer writes to an existing payment database behind a circuit breaker."
    },
    "verdict": "NOT READY"
  },

